module decoder_3to8 (  
    input wire [2:0] A,  
    input wire enable,  
    output reg [7:0] Y  
);  
    always @(*) begin  
        if (!enable)  
            Y = 8'b00000000;  
        else begin  
            case (A)  
                3'b000: Y = 8'b00000001;  
                3'b001: Y = 8'b00000010;  
                3'b010: Y = 8'b00000100;  
                3'b011: Y = 8'b00001000;  
                3'b100: Y = 8'b00010000;  
                3'b101: Y = 8'b00100000;  
                3'b110: Y = 8'b01000000;  
                3'b111: Y = 8'b10000000;  
                default: Y = 8'b00000000;  
            endcase  
        end  
    end  
  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~enable & A[0];
      Y[1] <= ~enable & A[1];
      Y[2] <= ~enable & A[2];
      Y[3] <= ~enable & A[0] & A[1];
      Y[4] <= ~enable & A[0] & A[2];
      Y[5] <= ~enable & A[1] & A[2];
      Y[6] <= ~enable & A[0] & A[1] & A[2];
      Y[7] <= ~enable;
    end
  end

endmodule
